+fn collect_text_blocks(blocks: &[ContentBlock]) -> String {
+    let mut out = String::new();
+    let mut first = true;
+    for block in blocks {
+        if let ContentBlock::Text(text) = block {
+            if !first {
+                out.push('\n');
+            }
+            out.push_str(&text.text);
+            first = false;
+        }
+    }
+    out
